import{_ as a,o as s,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"51. Salaries And Allowances","description":"","frontmatter":{"title":"51. Salaries And Allowances","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["wages"]},"headers":[],"relativePath":"ebas/mspp/classification-salaries/51-salaries-and-allowances.md","filePath":"ebas/mspp/classification-salaries/51-salaries-and-allowances.md"}'),t={name:"ebas/mspp/classification-salaries/51-salaries-and-allowances.md"};function r(l,e,i,p,c,h){return s(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_51-salaries-and-allowances" tabindex="-1">51. Salaries And Allowances <a class="header-anchor" href="#_51-salaries-and-allowances" aria-label="Permalink to &quot;51. Salaries And Allowances&quot;">​</a></h1><p><strong>51.1</strong> Salaries</p><p><strong>a.</strong> Each Employee is to be paid in accordance with the salary scale set out in work undertaken by the Employee.</p><p><strong>b.</strong> The salaries and allowances payable to Employees as set out in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a> have been adjusted by the following increases payable and to apply from the first pay period on or after (FFPPOA) 1 December 2021.</p><p><strong>c.</strong> The parties have agreed to increase the final year increment rate for all classifications by 0.50% and the salary increases at subclause d below are then added to these rates as set out in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>d.</strong> Salaries will be rounded to the nearest 10 cents. Allowances will be rounded to the nearest 5 cents.</p><p><strong>e.</strong> These salaries and allowances shall be increased as follows:</p><p><strong>(i)</strong> 2% effective first full pay period on or after (FFPPOA) 1 December 2021;</p><p><strong>(ii)</strong> 2% effective first full pay period on or after (FFPPOA) 1 December 2022;</p><p><strong>(iii)</strong> 2% effective first full pay period on or after (FFPPOA) 1 December 2023;</p><p><strong>(iv)</strong> 2% effective first full pay period on or after (FFPPOA) 1 December 2024.</p><p><strong>51.2</strong> Patience in Bargaining Lump Sum Payment - All Classification All Employees covered by this Agreement will receive a Lump Sum Patience in Bargaining payment of 2% of wages (all earnings) calculated between 1 July 2021 and 30 November 2021.</p><p><strong>51.3</strong> Annual Skills and Incentive Payment - All classifications except Psychologists</p><p><strong>a.</strong> All full-time Employees covered by this Agreement (except Psychology classifications) will receive an Annual Skills and Incentive Payment, as outlined below:</p><p><strong>(i)</strong> $1,000 on the FFPPOA 1 December 2021;</p><p><strong>(ii)</strong> $1,000 on the FFPPOA 1 December 2022;</p><p><strong>(iii)</strong> $1,000 on the FFPPOA 1 December 2023; and</p><p><strong>(iv)</strong> $1,000 on the FFPPOA 1 December 2024.</p><p><strong>b.</strong> The payments will be paid to part-time Employees on a pro-rata basis.</p><p><strong>c.</strong> The lump sum payments will not be made to casuals and locums.</p><p><strong>51.4</strong> Annual Retention Payment – Psychologists only</p><p><strong>a.</strong> All full-time Employees covered by this Agreement in Psychology classifications will receive an Annual Retention Payment, as outlined below:</p><p><strong>(i)</strong> $1,500 on the FFPPOA 1 November 2021;</p><p><strong>(ii)</strong> $1,800 on the FFPPOA 1 November 2022;</p><p><strong>(iii)</strong> $2,000 on the FFPPOA 1 November 2023; and</p><p><strong>(iv)</strong> $2,000 on the FFPPOA 1 November 2024.</p><p><strong>b.</strong> The payments will be paid to part-time Employees on a pro-rata basis.</p><p><strong>c.</strong> The lump sum payments will not be made to casuals and locums.</p><p><strong>51.5</strong> Salary Packaging All Employees covered by this Agreement will have access to salary packaging arrangements as follows:</p><p><strong>a.</strong> By written agreement with the Employee, the current salary specified in Employer policy on salary packaging.</p><p><strong>b.</strong> The Employee shall compensate the Employer from within their salary, for any Fringe Benefits Tax (FBT) incurred as a consequence of any salary packaging arrangement the Employee has entered into.</p><p><strong>c.</strong> The Parties agree that in the event that salary packaging ceases to be an advantage to the Employee (including as a result of subsequent changes to FBT legislation), the Employee may elect in writing to convert the amount packaged to salary. Any costs associated with the conversion to salary shall be borne by the Employee and the Employer shall not be liable to make up any benefit lost as a consequence of an Employee&#39;s decision to convert to salary.</p><p><strong>d.</strong> The Employee shall be responsible for all costs associated with salary packaging arrangements, including the administration costs provided that such administration costs shall be confined to reasonable commercial charges as levied directly by the external salary packaging provider and/or in-house payroll service (as applicable), as varied from time to time.</p><p><strong>e.</strong> Where the Employee chooses not to pay any of the costs associated with their salary packaging, the Employer may cease the Employee&#39;s salary packaging arrangements</p><p><strong>f.</strong> The Employers recommend that Employees who are considering salary packaging seek independent financial advice. The Employer shall not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>g.</strong> Where an Employee participates in salary packaging through an external salary packaging agency and terminates their employment, the final pay on termination may be delayed due to the reconciliation of their salary packaging account balance.</p><p><strong>51.6</strong> Allowances</p><p><strong>a.</strong> Meal Allowance An Employee shall be paid an allowance:</p><p><strong>(i)</strong> when required to work after the usual finishing hour of work beyond one hour (Monday to Friday inclusive) or in the case of shift workers when the overtime work on any shift exceeds one hour. Provided that</p><p>where such overtime work exceeds four hours a further meal allowance shall be paid;</p><p><strong>(ii)</strong> when recalled to duty outside of usual working hours for a period in excess of two hours (and when the time of such recall coincides with or over-runs Employees normal meal time). and where such overtime exceeds four hours a further meal allowance shall be paid.</p><p><strong>(iii)</strong> These allowances are specified in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>(iv)</strong> The meal allowance provisions shall not apply where a meal is supplied at the Employer’s expense.</p><p><strong>b.</strong> Lodging and rent (Pharmacists only)</p><p><strong>(i)</strong> Where the Employer provides board and lodging, the wage rates prescribed in this Agreement shall be reduced by the following amounts per week: $ Trainees 6.90 Others 15.20 Self-contained furnished accommodation 23.50 and except where the Employee buys their meals at ruling cafeteria rates, by an additional amount of $9.70.</p><p><strong>(ii)</strong> Where board and lodging is provided laundry shall also be provided free of charge, or full and adequate facilities for washing and ironing shall be provided.</p><p><strong>(iii)</strong> The expression board and lodging includes laundry provided free of charge.</p><p><strong>c.</strong> Removal Expenses (Psychologists Only)</p><p><strong>(i)</strong> An Employee transferred by their Employer to a location more than 60 kilometres from the location where they have been employed for at least two years shall be reimbursed reasonable removal expenses by the Employer to which they transfer.</p><p><strong>(ii)</strong> Provided that in such a case of Employer transfer where an Employee is required by their Employer to reside at a distance 60 kilometres from their former residence they shall be reimbursed reasonable removal expenses.</p><p><strong>d.</strong> Blood Check Allowance Any Employee exposed to radiation hazards in the course of their work shall be entitled to a blood count as often as is considered necessary and shall be reimbursed for any out of pocket expenses arising from such test.</p><p>Plain language terms: pay rates, wage rates, salary table.</p>',52)])])}const m=a(t,[["render",r]]);export{g as __pageData,m as default};
